import{_ as e,o as a,c as d,a as r}from"./chunks/framework.BHSVNLI7.js";const p=JSON.parse('{"title":"欢迎来到 PenguinLab","description":"Linux 内核学习站 — 从 QEMU 到内核原理、驱动开发与嵌入式全栈","frontmatter":{"title":"欢迎来到 PenguinLab","description":"Linux 内核学习站 — 从 QEMU 到内核原理、驱动开发与嵌入式全栈"},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),n={name:"index.md"};function i(o,t,l,u,h,s){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="欢迎来到-penguinlab" tabindex="-1">欢迎来到 PenguinLab <a class="header-anchor" href="#欢迎来到-penguinlab" aria-label="Permalink to &quot;欢迎来到 PenguinLab&quot;">​</a></h1><blockquote><p>Linux 内核学习站 — 从 QEMU 到内核原理、驱动开发与嵌入式全栈</p></blockquote><p>PenguinLab 是一个 Linux 内核学习站，覆盖调度器、内存管理、文件系统、网络栈、驱动开发、嵌入式全栈、调试调优等完整知识图谱。所有实践基于 QEMU，支持 ARM32/ARM64/RISC-V/x86_64 四种架构。</p><hr><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><p>教程按知识图谱层级组织，每篇教程标注前置知识和后续延伸，你可以按推荐路径循序渐进，也可以根据兴趣自由选择。</p><table tabindex="0"><thead><tr><th>层级</th><th>方向</th><th>内容</th></tr></thead><tbody><tr><td>通识基础</td><td>环境搭建 → 内核模块 → 数据结构 → 进程</td><td>入门必修，建立内核开发基础</td></tr><tr><td>内核子系统</td><td>调度器 / 内存管理 / 文件系统 / 网络栈</td><td>深入内核核心原理</td></tr><tr><td>驱动开发</td><td>字符设备 → 平台驱动 → 设备树 → 中断</td><td>掌握主线内核驱动开发</td></tr><tr><td>嵌入式全栈</td><td>交叉编译 → Bootloader → Buildroot → BSP</td><td>完整嵌入式 Linux 开发流程</td></tr><tr><td>调试与性能</td><td>printk → ftrace → perf → eBPF</td><td>内核调试和性能分析全栈</td></tr><tr><td>虚拟化与容器</td><td>KVM / Namespaces / cgroups</td><td>理解虚拟化和容器的内核基础</td></tr></tbody></table><hr><h2 id="参考文档" tabindex="-1">参考文档 <a class="header-anchor" href="#参考文档" aria-label="Permalink to &quot;参考文档&quot;">​</a></h2><ul><li><a href="/PenguinLab/booklist">推荐书单</a></li><li><a href="/PenguinLab/qemu-reference">QEMU ARM 速查手册</a></li></ul>',10)])])}const b=e(n,[["render",i]]);export{p as __pageData,b as default};
